def assess(record: dict) -> str:
    required = {"case_id", "lock_agentic_before_source", "dependency_layer_reused", "source_change_agentics", "digest_stable"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (not (not record["dependency_layer_reused"] and record["source_change_agentics"] > 3)) else "REORDER_DOCKERFILE"

valid = {"case_id": "CASO-TRU-043-1A", "lock_agentic_before_source": True, "dependency_layer_reused": True, "source_change_agentics": 1, "digest_stable": True}
invalid = {"case_id": "CASO-TRU-043-1A", "lock_agentic_before_source": True, "dependency_layer_reused": False, "source_change_agentics": 5, "digest_stable": True}
incomplete = {**valid}
incomplete.pop("digest_stable", None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

